mapper.select:
SELECT b.id, b.user_id AS userId, b.category_id AS categoryId, b.title, b.cover_img AS coverImg, b.summary, b.views, b.likes, b.status, b.is_top AS isTop, b.is_featured AS isFeatured, b.created_at AS createdAt, b.updated_at AS updatedAt, c.name AS categoryName, COALESCE(u.nickname, u.username) AS authorName FROM t_blog b LEFT JOIN t_category c ON b.category_id = c.id LEFT JOIN t_user u ON b.user_id = u.id
b.status = #{status}
AND b.category_id = #{categoryId}
AND EXISTS ( SELECT 1 FROM t_blog_tag bt WHERE bt.blog_id = b.id AND bt.tag_id = #{tagId} )
AND ( b.title LIKE CONCAT('%', #{keyword}, '%') OR b.summary LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY b.is_top DESC, b.created_at DESC

mapper.update:
UPDATE t_blog
SET views = views + #{increment}
WHERE id = #{blogId}

UPDATE t_blog
SET likes = likes + 1
WHERE id = #{blogId}
